import { useState, useEffect, useCallback } from "react";
import { TrendingUp, TrendingDown, RefreshCw, ExternalLink, AlertCircle } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Skeleton } from "@/components/ui/skeleton";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { cn } from "@/lib/utils";
import type { MarketSwing } from "./types";
import { getPolymarketSwings, getKalshiSwings } from "./lib/api";

type SourceFilter = "all" | "polymarket" | "kalshi";
type Status = "idle" | "loading" | "success" | "error";

export default function App() {
  const [swings, setSwings] = useState<MarketSwing[]>([]);
  const [filter, setFilter] = useState<SourceFilter>("all");
  const [pmStatus, setPmStatus] = useState<Status>("idle");
  const [kStatus, setKStatus] = useState<Status>("idle");
  const [pmError, setPmError] = useState("");
  const [kError, setKError] = useState("");
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  const fetchData = useCallback(async () => {
    setPmStatus("loading");
    setKStatus("loading");

    const allSwings: MarketSwing[] = [];

    // Fetch both in parallel
    const [pmResult, kResult] = await Promise.allSettled([
      getPolymarketSwings(),
      getKalshiSwings(),
    ]);

    if (pmResult.status === "fulfilled") {
      allSwings.push(...pmResult.value);
      setPmStatus("success");
      setPmError("");
    } else {
      setPmStatus("error");
      setPmError(pmResult.reason?.message || "Failed");
    }

    if (kResult.status === "fulfilled") {
      allSwings.push(...kResult.value);
      setKStatus("success");
      setKError("");
    } else {
      setKStatus("error");
      setKError(kResult.reason?.message || "Failed");
    }

    // Sort by absolute change descending
    allSwings.sort((a, b) => b.absChange - a.absChange);
    setSwings(allSwings);
    setLastUpdated(new Date());
  }, []);

  useEffect(() => {
    fetchData();
    const id = setInterval(fetchData, 5 * 60 * 1000);
    return () => clearInterval(id);
  }, [fetchData]);

  const isLoading = pmStatus === "loading" || kStatus === "loading";

  const filtered = swings.filter((s) => {
    if (filter === "all") return true;
    return s.source === filter;
  });

  const pmCount = swings.filter((s) => s.source === "polymarket").length;
  const kCount = swings.filter((s) => s.source === "kalshi").length;

  const statusDot = (status: Status) => {
    const color =
      status === "success"
        ? "bg-emerald-400"
        : status === "error"
        ? "bg-red-400"
        : status === "loading"
        ? "bg-amber-400 animate-pulse"
        : "bg-zinc-500";
    return <span className={cn("inline-block w-1.5 h-1.5 rounded-full", color)} />;
  };

  return (
    <div className="w-full h-full overflow-auto p-4 space-y-3">
      {/* Controls */}
      <div className="flex items-center justify-between gap-2 flex-wrap">
        <Tabs
          value={filter}
          onValueChange={(v) => setFilter(v as SourceFilter)}
        >
          <TabsList className="h-7 bg-zinc-800/60">
            <TabsTrigger value="all" className="text-xs h-5 px-2">
              All ({swings.length})
            </TabsTrigger>
            <TabsTrigger value="polymarket" className="text-xs h-5 px-2 gap-1">
              {statusDot(pmStatus)} PM ({pmCount})
            </TabsTrigger>
            <TabsTrigger value="kalshi" className="text-xs h-5 px-2 gap-1">
              {statusDot(kStatus)} Kalshi ({kCount})
            </TabsTrigger>
          </TabsList>
        </Tabs>

        <button
          onClick={fetchData}
          disabled={isLoading}
          className="flex items-center gap-1 text-[11px] text-zinc-400 hover:text-zinc-200 transition-colors disabled:opacity-50"
        >
          <RefreshCw className={cn("w-3 h-3", isLoading && "animate-spin")} />
          {lastUpdated
            ? `${lastUpdated.toLocaleTimeString([], {
                hour: "2-digit",
                minute: "2-digit",
              })}`
            : "LoadingÃ¢â‚¬Â¦"}
        </button>
      </div>

      {/* Error alerts */}
      {pmStatus === "error" && (
        <Alert variant="destructive" className="py-2 px-3">
          <AlertCircle className="h-3 w-3" />
          <AlertDescription className="text-xs">
            Polymarket: {pmError}
          </AlertDescription>
        </Alert>
      )}
      {kStatus === "error" && (
        <Alert variant="destructive" className="py-2 px-3">
          <AlertCircle className="h-3 w-3" />
          <AlertDescription className="text-xs">
            Kalshi: {kError}
          </AlertDescription>
        </Alert>
      )}

      {/* Loading skeleton */}
      {isLoading && swings.length === 0 && (
        <div className="space-y-2">
          {Array.from({ length: 8 }).map((_, i) => (
            <Skeleton key={i} className="h-14 w-full bg-zinc-800/50" />
          ))}
        </div>
      )}

      {/* Results */}
      {filtered.length > 0 && (
        <div className="space-y-1">
          {filtered.map((swing, i) => (
            <SwingRow key={swing.id} swing={swing} rank={i + 1} />
          ))}
        </div>
      )}

      {!isLoading && filtered.length === 0 && swings.length > 0 && (
        <p className="text-xs text-zinc-500 text-center py-8">
          No swings for this filter.
        </p>
