  const barWidth = Math.min(swing.absChange * 2, 100);

  return (
    <a
      href={swing.url}
      target="_blank"
      rel="noopener noreferrer"
      className="group block relative overflow-hidden bg-zinc-900/50 hover:bg-zinc-800/60 border border-zinc-800/50 hover:border-zinc-700/60 transition-all"
    >
