        style={{ width: `${barWidth}%` }}
      />

      <div className="relative flex items-center gap-3 px-3 py-2.5">
        {/* Rank */}
        <span className="text-[10px] text-zinc-600 w-4 text-right shrink-0 tabular-nums">
          {rank}
        </span>

        {/* Change indicator */}
        <div
          className={cn(
            "flex items-center gap-0.5 shrink-0 w-[72px]",
            isUp ? "text-emerald-400" : "text-red-400"
          )}
        >
          {isUp ? (
            <TrendingUp className="w-3.5 h-3.5" />
          ) : (
            <TrendingDown className="w-3.5 h-3.5" />
          )}
          <span className="text-sm font-semibold tabular-nums">
            {isUp ? "+" : ""}
            {swing.change.toFixed(1)}
          </span>
          <span className="text-[10px] opacity-60">pp</span>
        </div>

        {/* Question + meta */}
        <div className="flex-1 min-w-0">
          <p className="text-xs text-zinc-200 truncate leading-snug group-hover:text-white transition-colors">
            {swing.question}
          </p>
          <div className="flex items-center gap-2 mt-0.5">
            <Badge
              variant="outline"
              className={cn(
                "text-[9px] h-3.5 px-1 border-0",
                swing.source === "polymarket"
                  ? "bg-violet-500/15 text-violet-400"
                  : "bg-sky-500/15 text-sky-400"
              )}
            >
              {swing.source === "polymarket" ? "PM" : "K"}
            </Badge>
            <span className="text-[10px] text-zinc-500 tabular-nums">
              {swing.previousProb.toFixed(0)}%→{swing.currentProb.toFixed(0)}%
            </span>
            {swing.volume24h > 0 && (
              <span className="text-[10px] text-zinc-600 tabular-nums">
                ${formatVolume(swing.volume24h)}
              </span>
            )}
          </div>
        </div>

        {/* Current probability */}
        <div className="text-right shrink-0">
          <span className="text-sm font-semibold text-zinc-100 tabular-nums">
            {swing.currentProb.toFixed(0)}
            <span className="text-[10px] text-zinc-500">%</span>
          </span>
        </div>

        {/* External link icon */}
        <ExternalLink className="w-3 h-3 text-zinc-600 group-hover:text-zinc-400 transition-colors shrink-0" />
      </div>
    </a>
  );
}

function formatVolume(v: number): string {
  if (v >= 1_000_000) return (v / 1_000_000).toFixed(1) + "M";
  if (v >= 1_000) return (v / 1_000).toFixed(0) + "K";
  return v.toFixed(0);
}
